import SwiftUI

struct LayoutDemo: View {
    var body: some View {
        VStack(spacing: 20) {
            // Header
            Text("Dashboard")
                .font(.largeTitle)
                .fontWeight(.bold)

            // Cards row
            HStack(spacing: 16) {
                StatCard(title: "Lessons", value: "12", icon: "book.fill")
                StatCard(title: "Streak", value: "5", icon: "flame.fill")
                StatCard(title: "Points", value: "450", icon: "star.fill")
            }

            // Progress section
            VStack(alignment: .leading, spacing: 8) {
                Text("Your Progress")
                    .font(.headline)
                ProgressView(value: 0.65)
                    .tint(.blue)
                Text("65% Complete")
                    .font(.caption)
                    .foregroundColor(.secondary)
            }
            .padding()
            .background(Color(.systemGray6))
            .cornerRadius(12)
        }
        .padding()
    }
}

struct StatCard: View {
    let title: String
    let value: String
    let icon: String

    var body: some View {
        VStack(spacing: 8) {
            Image(systemName: icon)
                .font(.title2)
                .foregroundColor(.blue)
            Text(value)
                .font(.title)
                .fontWeight(.bold)
            Text(title)
                .font(.caption)
                .foregroundColor(.secondary)
        }
        .frame(maxWidth: .infinity)
        .padding()
        .background(Color(.systemGray6))
        .cornerRadius(12)
    }
}

